package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.util.Arrays;
import java.util.List;

class CartTest {

  @Test
  void testGetLineItems() {
    LineItem item1 = new LineItem(); // Assuming LineItem has a no-arg constructor
    LineItem item2 = new LineItem();
    List<LineItem> items = Arrays.asList(item1, item2);
    Cart cart = new Cart(items, "buyerName", "1234-5678-9876-5432");

    List<LineItem> result = cart.getLineItems();

    assertNotNull(result);
    assertEquals(2, result.size());
    assertSame(item1, result.get(0));
    assertSame(item2, result.get(1));
  }
}
